const whatsapp = $node["Webhook"].json["body"]["Whatsapp"] || '';
const cpfRaw =  $input.first().json.body.CPF || '';

telefone = whatsapp.toString().replace(/[^\d]/g, ''); // remove tudo que não for número

// Se o telefone tiver 11 dígitos (DDD + número), adiciona 55
if (telefone.length === 11) {
  telefone = '55' + telefone;
} 
// Se já tiver 13 dígitos e começar com 55, mantém como está
else if (telefone.length === 13 && telefone.startsWith('55')) {
  // já está correto
} 
// Se for telefone com 10 dígitos (sem o 9 no começo), adiciona 55
else if (telefone.length === 10) {
  telefone = '55' + telefone;
}
// Se for um número com comprimento inesperado, apenas mantém limpo
else {
  telefone = telefone;
}

// Formatar CPF como texto (apenas números)
const cpf = cpfRaw.toString().replace(/[^\d]/g, '');

const result = {
    whatsapp: telefone,
    cpf: cpf
};

// Retorno no formato esperado pelo n8n
return [{ json: result }];

